INSERT INTO public.supplements (id, name, dosage, evidence_level, benefits, concerns_treated, interactions, pregnancy_safe) VALUES
  ('zinc_acne', 'Zinc', '15-45 mg elemental daily (acne: 25-30 mg as picolinate with 2-3 mg copper)', 'B', '["Inhibits 5-alpha reductase (reduces DHT)","Anti-inflammatory (reduces IL-6, TNF-alpha)","Inhibits P. acnes growth","Reduces sebum production","Antioxidant (SOD cofactor)","Supports hair protein synthesis","Supports hair follicle cycling"]'::jsonb, '["acne","hair_loss"]'::jsonb, '["Tetracyclines and fluoroquinolones (separate by 2-4 hours)","Penicillamine (reduces absorption)","Iron (competitive absorption)","Thiazide diuretics (increase excretion)","Isotretinoin (may increase zinc needs)"]'::jsonb, 'Generally safe at RDA levels (11 mg elemental). Avoid high-dose supplementation without physician oversight.'),
  ('omega3_epa_dha', 'Omega-3 EPA/DHA', '1,000-3,000 mg EPA+DHA combined daily (acne: 2,000 mg; anti-inflammatory threshold ~2,000 mg)', 'B', '["Reduces pro-inflammatory eicosanoids (PGE2, LTB4)","Inhibits IL-1, IL-6, TNF-alpha","May reduce IGF-1 signaling","Improves insulin sensitivity","Supports skin barrier function","Reduces inflammatory eicosanoids","Modulates Th1/Th2 balance","Reduces itch-scratch cycle"]'::jsonb, '["acne","eczema","aging"]'::jsonb, '["Warfarin, aspirin, clopidogrel (monitor INR/bleeding at >3 g/day)","Blood pressure medications (may potentiate hypotensive effects)","Orlistat (reduces absorption)"]'::jsonb, 'Generally safe and beneficial. Limit to ≤3,000 mg EPA+DHA combined. Essential for fetal neural development (DHA).'),
  ('vitamin_a', 'Vitamin A', '≤5,000-10,000 IU retinol daily (short-term, monitored); prefer dietary sources', 'C', '["Normalizes keratinization (reduces follicular plugging)","Reduces sebum production","Anti-inflammatory","Supports immune function in skin"]'::jsonb, '["acne"]'::jsonb, '["Isotretinoin/tretinoin (additive toxicity — NEVER combine without dermatologist)","Hepatotoxic drugs (alcohol, methotrexate, acetaminophen)","Orlistat (reduces absorption)"]'::jsonb, 'CONTRAINDICATED. Do NOT use retinol supplements if pregnant, planning pregnancy, or breastfeeding. Beta-carotene is safe but ineffective for acne.'),
  ('probiotics', 'Probiotics', '10-50 billion CFU daily (acne: 25-50B multi-strain; eczema: 25-50B with LGG)', 'B', '["Gut microbiome modulation (gut-skin axis)","Reduces systemic inflammation","Modulates IGF-1 and insulin signaling","Produces antimicrobial peptides","Strengthens intestinal barrier","T-regulatory cell enhancement","Produces SCFAs (butyrate)"]'::jsonb, '["acne","eczema"]'::jsonb, '["Antibiotics (separate by 2+ hours)","Antifungals (may reduce efficacy)","Immunosuppressants (use caution)"]'::jsonb, 'Generally considered safe; LGG specifically studied in pregnancy for eczema prevention in offspring.'),
  ('dim', 'DIM (Diindolylmethane)', '200-300 mg standard DIM or 150 mg BR-DIM daily', 'C', '["Modulates estrogen metabolism (favors 2-hydroxyestrone)","Mild anti-androgen effects","Supports liver estrogen detoxification","Anti-inflammatory","May reduce sebum production in hormonal acne"]'::jsonb, '["acne"]'::jsonb, '["Hormonal contraceptives (may theoretically reduce efficacy)","Tamoxifen (similar pathways — avoid)","CYP450 inducers (may interact with various medications)"]'::jsonb, 'NOT RECOMMENDED — hormonal effects unknown; avoid.'),
  ('saw_palmetto_acne', 'Saw Palmetto', '320 mg standardized extract daily (85-95% fatty acids and sterols)', 'C', '["Inhibits 5-alpha reductase (Type I and II)","Anti-androgen effects","Anti-inflammatory","May reduce sebum production","May prolong anagen (growth) phase"]'::jsonb, '["acne","hair_loss"]'::jsonb, '["Finasteride/dutasteride (additive 5-AR inhibition)","Hormonal contraceptives (theoretical interaction)","Anticoagulants (may have mild antiplatelet effects)"]'::jsonb, 'NOT RECOMMENDED — anti-androgen effects; avoid.'),
  ('spearmint', 'Spearmint', '2 cups strong tea daily (steep 5-10 min) OR 400-600 mg capsules', 'C', '["Anti-androgen (reduces free testosterone)","Increases LH and FSH","Antioxidant","Anti-inflammatory"]'::jsonb, '["acne"]'::jsonb, '["Hormonal medications (theoretical interaction)","Liver-metabolized drugs (menthol compounds may affect CYP enzymes)"]'::jsonb, 'Limited data; avoid high doses. Tea in moderation likely safe.'),
  ('berberine', 'Berberine', '500 mg 2-3 times daily (1,000-1,500 mg total); start once daily and titrate up', 'B', '["Improves insulin sensitivity (metformin-like effects)","Reduces IGF-1 and androgen signaling","Anti-inflammatory","Antimicrobial (modulates gut microbiome)","Supports hormonal balance in PCOS"]'::jsonb, '["acne"]'::jsonb, '["CYP3A4 substrates (many medications — berberine inhibits this enzyme)","Metformin (additive hypoglycemic effects)","Anticoagulants (may affect platelet function)","Macrolide antibiotics (additive QT prolongation risk)","Cyclosporine (increased levels)","Sedatives (may potentiate effects)"]'::jsonb, 'CONTRAINDICATED — may cause uterine contractions; kernicterus risk in newborns.'),
  ('vitamin_c', 'Vitamin C', '500-1,000 mg daily (skin health); 1,000 mg daily for hyperpigmentation; photoprotection 500 mg 2x/day with vitamin E', 'B', '["Essential cofactor for collagen synthesis","Potent antioxidant (neutralizes ROS from UV)","Regenerates oxidized vitamin E","Inhibits tyrosinase (melanin production)","Anti-inflammatory","Enhances iron absorption"]'::jsonb, '["aging","hyperpigmentation"]'::jsonb, '["Iron (significantly enhances absorption — separate if iron overload concern)","Chemotherapy (antioxidant interactions complex; consult oncologist)","Statins (may reduce efficacy — limited evidence)","Warfarin (high-dose may reduce efficacy — monitor INR)"]'::jsonb, 'Safe at standard doses (85-120 mg RDA). Avoid megadoses (>2,000 mg).'),
  ('niacinamide', 'Niacinamide', '500 mg 1-2 times daily (up to 1,000 mg/day); topical niacinamide (2-10%) is first-line, oral is adjunct', 'C', '["Anti-inflammatory (reduces IL-1, IL-8, TNF-alpha)","Regulates sebum production","Improves barrier function","Antioxidant","Inhibits melanosome transfer (hyperpigmentation benefit)"]'::jsonb, '["acne","hyperpigmentation"]'::jsonb, '["Carbamazepine (niacinamide may increase levels)","Primidone (may reduce efficacy)","Anticoagulants (high-dose may affect platelets)"]'::jsonb, 'Safe at standard doses; essential nutrient.'),
  ('glutathione', 'Glutathione', '250-500 mg liposomal glutathione daily (oral only; do NOT recommend IV)', 'C', '["Master antioxidant (reduces oxidative stress driving pigmentation)","Inhibits tyrosinase (direct melanin inhibition)","Promotes melanin shift from eumelanin to pheomelanin","Detoxification support","Anti-inflammatory"]'::jsonb, '["hyperpigmentation"]'::jsonb, '["Chemotherapy (may interfere with treatments — avoid during chemotherapy)","Nitroglycerin (glutathione may potentiate effects)","Acetaminophen (NAC is antidote for overdose)"]'::jsonb, 'Avoid — insufficient safety data.'),
  ('tranexamic_acid', 'Tranexamic Acid', '250-500 mg 2-3 times daily (500-1,500 mg total); melasma: 250 mg BID preferred for safety', 'B', '["Plasmin inhibitor (reduces arachidonic acid pathway)","Reduces UV-induced melanin synthesis","Inhibits tyrosinase","Anti-inflammatory","Reduces melanocyte-keratinocyte interaction"]'::jsonb, '["hyperpigmentation"]'::jsonb, '["Hormonal contraceptives (increased thrombosis risk — avoid combination)","Hormone replacement therapy (same concern)","Anticoagulants (may reduce efficacy or increase bleeding)","Tretinoin (may enhance effects topically)"]'::jsonb, 'CONTRAINDICATED — potential thrombotic risk.'),
  ('marine_collagen_skin', 'Marine Collagen', '5-10 g daily of Type I/III hydrolyzed collagen; hair growth: 5-10 g daily', 'C', '["Provides building blocks for collagen synthesis","Stimulates fibroblasts to produce new collagen","Increases skin hydration and elasticity","Contains proline, glycine, hydroxyproline","Bioactive peptides may have signaling effects","Provides amino acid building blocks for keratin","Supports hair follicle protein synthesis","May improve scalp health"]'::jsonb, '["aging","hair_loss"]'::jsonb, '["Minimal known interactions"]'::jsonb, 'Generally considered safe; food-derived. Fish/shellfish allergy caution for marine sources.'),
  ('coq10', 'CoQ10 (Coenzyme Q10)', '100-200 mg ubiquinol daily (or 200-400 mg ubiquinone if under 40)', 'C', '["Mitochondrial energy production (ATP synthesis)","Lipid-soluble antioxidant","Protects against oxidative stress","Supports skin cell repair","Reduces UV-induced damage","Replenishes ubiquinol depleted by statins"]'::jsonb, '["aging"]'::jsonb, '["Statins (CoQ10 depleted by statins — supplementation essential for statin users)","Warfarin (theoretical interaction — monitor INR)","Chemotherapy (antioxidant effects may interfere — consult oncologist)","Blood pressure meds (may potentiate hypotensive effects)"]'::jsonb, 'Limited data; generally considered safe but consult physician.'),
  ('astaxanthin', 'Astaxanthin', '4-6 mg daily (general); 6-12 mg daily (skin/UV protection)', 'B', '["6,000x stronger antioxidant than vitamin C","550x stronger than vitamin E","Crosses blood-brain and blood-retinal barriers","Reduces ROS and lipid peroxidation","Anti-inflammatory","Improves skin elasticity and hydration","Reduces UV-induced skin damage","May improve skin moisture barrier"]'::jsonb, '["aging"]'::jsonb, '["Anticoagulants (very high doses may have mild antiplatelet effects — rare at standard doses)","Hormonal therapies (may affect hormone metabolism — limited evidence)"]'::jsonb, 'Limited data; likely safe at 4-6 mg but consult physician.'),
  ('resveratrol', 'Resveratrol', '250-500 mg trans-resveratrol daily (micronized or with piperine for absorption)', 'C', '["SIRT1 activation (longevity pathway)","Potent antioxidant","Anti-inflammatory","Improves mitochondrial function","May protect against UV damage","Supports collagen synthesis"]'::jsonb, '["aging"]'::jsonb, '["Anticoagulants (may increase bleeding risk — theoretical)","CYP3A4 substrates (resveratrol may inhibit metabolism)","Blood pressure medications (may potentiate effects)"]'::jsonb, 'NOT RECOMMENDED — limited safety data; theoretical hormonal effects.'),
  ('hyaluronic_acid', 'Hyaluronic Acid', '120-200 mg daily', 'C', '["Increases skin hydration and elasticity","Supports skin moisture barrier","May reduce appearance of fine lines"]'::jsonb, '["aging"]'::jsonb, '["Minimal known interactions"]'::jsonb, 'Limited data; generally considered safe but consult physician.'),
  ('evening_primrose_oil', 'Evening Primrose Oil', '1,000-2,000 mg EPO daily (provides 80-200 mg GLA); children: 500-1,000 mg', 'C', '["GLA → DGLA → anti-inflammatory prostaglandin E1 (PGE1)","Supports skin barrier function","Reduces inflammation","Some eczema patients have impaired delta-6-desaturase"]'::jsonb, '["eczema"]'::jsonb, '["Anticoagulants (potential additive effect at high doses)","Anticonvulsants (theoretical interaction)","Phenothiazines (may lower seizure threshold — rare)"]'::jsonb, 'Generally safe; GLA present in breast milk naturally. Avoid high doses.'),
  ('vitamin_d3', 'Vitamin D3', '2,000-4,000 IU daily (adjust based on 25(OH)D levels); maintenance 1,000-2,000 IU', 'B', '["Regulates immune function (T-regulatory cells)","Supports skin barrier function (filaggrin expression)","Anti-inflammatory","Antimicrobial (cathelicidin production)","Modulates Th1/Th2/Th17 responses"]'::jsonb, '["eczema"]'::jsonb, '["Thiazide diuretics (may increase hypercalcemia risk)","Corticosteroids (may deplete vitamin D)","Orlistat (reduces absorption)","Cholestyramine (reduces absorption)"]'::jsonb, 'Essential; safe at standard doses (4,000-6,000 IU for lactating mothers).'),
  ('quercetin', 'Quercetin', '500-1,000 mg standard daily; quercetin phytosome 250-500 mg; EMIQ 200-400 mg', 'C', '["Mast cell stabilizer (reduces histamine release)","Anti-inflammatory (inhibits COX, LOX, NF-kB)","Antioxidant","Reduces itch-scratch cycle","Modulates Th1/Th2 immune response"]'::jsonb, '["eczema"]'::jsonb, '["Anticoagulants (may have mild antiplatelet effects)","CYP3A4 substrates (may inhibit metabolism)","Quinolone antibiotics (may reduce absorption)","Cyclosporine (may increase levels)"]'::jsonb, 'Limited data; avoid high doses.'),
  ('biotin', 'Biotin', '2,500-10,000 mcg daily (only if deficiency suspected); RDA 30 mcg', 'D', '["Cofactor for keratin synthesis","Supports hair protein structure","Cell proliferation in hair follicle"]'::jsonb, '["hair_loss"]'::jsonb, '["Anticonvulsants (may deplete biotin — long-term use)","Isotretinoin (may affect biotinidase)","LAB TESTS: causes false results on TSH, troponin, HCG, many immunoassays — stop 48-72 hours before blood work"]'::jsonb, 'Safe; RDA increases to 35 mcg during lactation. CRITICAL: stop before blood work.'),
  ('iron', 'Iron', '25-65 mg elemental iron 1-2 times daily (only if deficient); ferritin target for hair growth >40 ng/mL (ideally 70-100)', 'B', '["Essential for DNA synthesis in rapidly dividing hair follicle cells","Ribonucleotide reductase cofactor","Supports oxygen delivery to hair follicles","Ferritin directly involved in hair follicle cycling"]'::jsonb, '["hair_loss"]'::jsonb, '["Antacids/PPIs (reduce absorption significantly)","Thyroid medication (separate by 4 hours — iron reduces levothyroxine absorption)","Antibiotics (tetracyclines, fluoroquinolones, penicillamine — separate by 2-4 hours)","Bisphosphonates (separate by 2+ hours)","Calcium (competes for absorption — separate)","Zinc (competes for absorption — separate)","Copper (high-dose iron depletes copper)"]'::jsonb, 'Iron needs increase; standard prenatal contains 27-30 mg. Safe at standard doses. Do NOT take without confirmed deficiency.'),
  ('colostrum', 'Bovine Colostrum', '2-4g powder daily (standard); 1-2g of 40% IgG concentrate (optimized). Morning, empty stomach or with light meal.', 'C', '["Rich in immunoglobulins (IgG, IgA) — systemic immune modulation","Lactoferrin — antimicrobial (iron chelation), anti-inflammatory, barrier support","Growth factors (IGF-1, TGF-β) — tissue repair, wound healing, collagen synthesis","Proline-rich polypeptides (PRPs) — immune modulation","Supports gut barrier integrity (tight junctions)","Reduces intestinal permeability","Modulates inflammatory cytokine production"]'::jsonb, '["acne","eczema","rosacea","aging"]'::jsonb, '["Dairy allergy (contraindicated)","Immunosuppressants (theoretical concern — consult physician)","No known drug interactions at standard doses"]'::jsonb, 'Limited data; theoretical benefit but insufficient safety studies. Consult physician before use during pregnancy or breastfeeding.')
